// On récupère le premier item entrant (le gros JSON)
const input = $input.first().json;
const keywords = input.output.keywords;
const batchSize = 25;
const batches = [];

// On prépare les paquets
for (let i = 0; i < keywords.length; i += batchSize) {
    batches.push({
        json: {
            Theme: input.Theme,
            Niche: input.Niche,
            SubNiche: input.SubNiche,
            ProductType: input.ProductType,
            Description: input.Description,
            visual_aesthetic:input.visual_aesthetic,
            visual_typography:input.visual_typography,
            visual_graphics:input.visual_graphics,
            visual_colors: input.visual_colors,
            visual_target_audience: input.visual_target_audience,
            visual_overall_vibe: input.visual_overall_vibe,


            // On envoie un morceau de la liste
            keywordsBatch: keywords.slice(i, i + batchSize)
        }
    });
}

// n8n va maintenant voir X items (batches) et pourra les traiter en parallèle
return batches;

// On récupère tous les batches (les 8 items)
const allItems = $input.all();
let combinedKeywords = [];

// On boucle sur chaque batch pour extraire les keywords scorés
for (const item of allItems) {
    if (item.json.output && item.json.output.keywords) {
        combinedKeywords = combinedKeywords.concat(item.json.output.keywords);
    }
}

// On renvoie un objet unique contenant la liste totale
return {
    total_keywords: combinedKeywords.length,
    keywords: combinedKeywords
};
